267: // Enumerate observers of aTopic and call Observe on each.
268: NS_IMETHODIMP nsObserverService::NotifyObservers(nsISupports* aSubject,
269:                                                  const char* aTopic,
270:                                                  const char16_t* aSomeData) {
271:   LOG(("nsObserverService::NotifyObservers(%s)", aTopic));
272: 
273:   MOZ_TRY(EnsureValidCall());
274:   if (NS_WARN_IF(!aTopic)) {
275:     return NS_ERROR_INVALID_ARG;
276:   }
277: 
278:   MOZ_ASSERT(AppShutdown::IsNoOrLegalShutdownTopic(aTopic));
279: 
280:   AUTO_PROFILER_MARKER_TEXT("NotifyObservers", OTHER, MarkerStack::Capture(),
281:                             nsDependentCString(aTopic));
282:   AUTO_PROFILER_LABEL_DYNAMIC_CSTR_NONSENSITIVE(
283:       "nsObserverService::NotifyObservers", OTHER, aTopic);
284: 
285:   nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
286:   if (observerList) {
287:     observerList->NotifyObservers(aSubject, aTopic, aSomeData);
288:   }
289: 
290:   return NS_OK;
291: }
292: 
293: NS_IMETHODIMP
294: nsObserverService::UnmarkGrayStrongObservers() {
295:   MOZ_TRY(EnsureValidCall());
296: 
297:   nsCOMArray<nsIObserver> strongObservers;
298:   for (auto iter = mObserverTopicTable.Iter(); !iter.Done(); iter.Next()) {
299:     nsObserverList* aObserverList = iter.Get();
300:     if (aObserverList) {
301:       aObserverList->AppendStrongObservers(strongObservers);
302:     }
303:   }
304: 
305:   for (uint32_t i = 0; i < strongObservers.Length(); ++i) {
306:     xpc_TryUnmarkWrappedGrayObject(strongObservers[i]);
307:   }
308: 
309:   return NS_OK;
310: }
311: 
312: bool nsObserverService::HasObservers(const char* aTopic) {
313:   return mObserverTopicTable.Contains(aTopic);
314: }
