318: class NotifyWhenScriptSafeRunnable : public mozilla::Runnable {
319:  public:
320:   NotifyWhenScriptSafeRunnable(nsIObserverService* aObs, nsISupports* aSubject,
321:                                const char* aTopic, const char16_t* aData)
322:       : mozilla::Runnable("NotifyWhenScriptSafeRunnable"),
323:         mObs(aObs),
324:         mSubject(aSubject),
325:         mTopic(aTopic) {
326:     if (aData) {
327:       mData.Assign(aData);
328:     } else {
329:       mData.SetIsVoid(true);
330:     }
331:   }
332: 
333:   NS_IMETHOD Run() override {
334:     const char16_t* data = mData.IsVoid() ? nullptr : mData.get();
335:     return mObs->NotifyObservers(mSubject, mTopic.get(), data);
336:   }
337: 
338:  private:
339:   nsCOMPtr<nsIObserverService> mObs;
340:   nsCOMPtr<nsISupports> mSubject;
341:   nsCString mTopic;
342:   nsString mData;
343: };
344: 
345: }  // namespace
346: 
347: nsresult nsIObserverService::NotifyWhenScriptSafe(nsISupports* aSubject,
348:                                                   const char* aTopic,
349:                                                   const char16_t* aData) {
350:   if (nsContentUtils::IsSafeToRunScript()) {
351:     return NotifyObservers(aSubject, aTopic, aData);
352:   }
353: 
354:   nsContentUtils::AddScriptRunner(MakeAndAddRef<NotifyWhenScriptSafeRunnable>(
355:       this, aSubject, aTopic, aData));
356:   return NS_OK;
357: }
