85: NS_IMETHODIMP nsAlertsService::ShowAlert(nsIAlertNotification* aAlert,
86:                                          nsIObserver* aAlertListener) {
87:   NS_ENSURE_ARG(aAlert);
88: 
89:   nsAutoString cookie;
90:   nsresult rv = aAlert->GetCookie(cookie);
91:   NS_ENSURE_SUCCESS(rv, rv);
92: 
93:   if (AppShutdown::IsInOrBeyond(ShutdownPhase::AppShutdownConfirmed)) {
94:     // Bailing out without calling alertfinished, because we do not want to
95:     // propagate an error to observers during shutdown.
96:     return NS_OK;
97:   }
98: 
99:   // Check if there is an optional service that handles system-level
100:   // notifications
101:   if (StaticPrefs::alerts_useSystemBackend()) {
102:     if (!mBackend) {
103:       return NS_ERROR_NOT_AVAILABLE;
104:     }
105:     return mBackend->ShowAlert(aAlert, aAlertListener);
106:   }
107: 
108:   if (!ShouldShowAlert()) {
109:     // Do not display the alert. Instead call alertfinished and get out.
110:     if (aAlertListener) {
111:       aAlertListener->Observe(nullptr, "alertfinished", cookie.get());
112:     }
113:     return NS_OK;
114:   }
115: 
116:   // Use XUL notifications as a fallback if above methods have failed.
117:   nsCOMPtr<nsIAlertsService> xulBackend(nsXULAlerts::GetInstance());
118:   NS_ENSURE_TRUE(xulBackend, NS_ERROR_FAILURE);
